  ('2a500532-b6a4-4b01-9456-c392d9df480f', 'Refine 2nd Edition', '数学Ｃ', '7', '7', 'Chapter 7', '3', '行列と行列式 Q3（中）', '((1,0),(2,1))((x),(y))=((3),(5)) を満たす (x,y) を求めよ。', null, '{}'::jsonb, '[{"id":"csv_2a500532-b6a4-4b01-9456-c392d9df480f_question_title","type":"heading","page":"question","x":24,"y":24,"w":360,"h":36,"text":"行列と行列式 Q3（中）"},{"id":"csv_2a500532-b6a4-4b01-9456-c392d9df480f_question_body","type":"question","page":"question","x":24,"y":72,"w":392,"h":96,"text":"((1,0),(2,1))((x),(y))=((3),(5)) を満たす (x,y) を求めよ。"},{"id":"csv_2a500532-b6a4-4b01-9456-c392d9df480f_question_choices","type":"text","page":"question","x":24,"y":184,"w":392,"h":92,"text":"A: (3,-1)\nB: (5,-1)\nC: (3,1)"},{"id":"csv_2a500532-b6a4-4b01-9456-c392d9df480f_text_explanation","type":"text","page":"text","x":24,"y":72,"w":392,"h":180,"text":"第1行より x=3。第2行は 2x+y=5 だから 6+y=5 で y=-1。Bは第1行を見落とした誤り、Cは y の符号計算ミス。参照定理：行列方程式と連立一次方程式"}]'::jsonb, '{"binder":"Refine 2nd Edition","note":"数学Ｃ","chapter":"7","section":"","textNumber":"7","textName":"Chapter 7","questionNumber":"3","questionName":"行列と行列式 Q3（中）","contentText":"((1,0),(2,1))((x),(y))=((3),(5)) を満たす (x,y) を求めよ。","contentHtml":"","notebookBlocks":[{"id":"csv_2a500532-b6a4-4b01-9456-c392d9df480f_question_title","type":"heading","page":"question","x":24,"y":24,"w":360,"h":36,"text":"行列と行列式 Q3（中）"},{"id":"csv_2a500532-b6a4-4b01-9456-c392d9df480f_question_body","type":"question","page":"question","x":24,"y":72,"w":392,"h":96,"text":"((1,0),(2,1))((x),(y))=((3),(5)) を満たす (x,y) を求めよ。"},{"id":"csv_2a500532-b6a4-4b01-9456-c392d9df480f_question_choices","type":"text","page":"question","x":24,"y":184,"w":392,"h":92,"text":"A: (3,-1)\nB: (5,-1)\nC: (3,1)"},{"id":"csv_2a500532-b6a4-4b01-9456-c392d9df480f_text_explanation","type":"text","page":"text","x":24,"y":72,"w":392,"h":180,"text":"第1行より x=3。第2行は 2x+y=5 だから 6+y=5 で y=-1。Bは第1行を見落とした誤り、Cは y の符号計算ミス。参照定理：行列方程式と連立一次方程式"}],"answerType":"choice","answers":["A: (3,-1)"],"choices":["A: (3,-1)","B: (5,-1)",